// Extract MEXC USDT symbols, filter to clean alphabetic ones (likely Solana tokens)
const seen = new Set();
const items = [];
for (const item of $input.all()) {
  const t = item.json;
  if (typeof t.symbol !== 'string' || !t.symbol.endsWith('USDT')) continue;
  const sym = t.symbol.slice(0, -4);
  if (!seen.has(sym) && /^[A-Z]{2,10}$/.test(sym)) {
    seen.add(sym);
    items.push({ json: { symbol: sym, mexcPrice: parseFloat(t.price) } });
  }
}
return items;

const jupItems = $input.all();
const tokenItems = $('Build MEXC Map').all();

// Build MEXC lookup: symbol → mexcPrice
const mexcLookup = {};
for (const item of tokenItems) {
  mexcLookup[item.json.symbol] = item.json.mexcPrice;
}

const common = [];
const seenMints = new Set();

for (const jupItem of jupItems) {
  const r = jupItem.json;
  const sym = (r.symbol || '').toUpperCase();

  if (!mexcLookup[sym] || !r.id || seenMints.has(r.id)) continue;

  const mexcPrice = mexcLookup[sym];
  const jupPrice = parseFloat(r.usdPrice || 0);

  // Price sanity filter: Jupiter price must be within 5% of MEXC price
  // (eliminates false matches where same symbol = different asset)
  if (jupPrice <= 0 || Math.abs((mexcPrice - jupPrice) / jupPrice) > 0.05) continue;

  seenMints.add(r.id);

  const stats24h = r.stats24h || {};
  const jup_volume_24h = (stats24h.buyVolume || 0) + (stats24h.sellVolume || 0);
  const jup_liquidity = r.liquidity || 0;

  common.push({
    symbol: sym,
    mint: r.id,
    name: r.name || sym,
    decimals: r.decimals ?? null,
    mexc_price: mexcPrice,
    jup_price: jupPrice,
    jup_volume_24h,
    jup_liquidity,
    tags: Array.isArray(r.tags) ? r.tags.join(',') : '',
    updated_at: new Date().toISOString()
  });
}

common.sort((a, b) => a.symbol.localeCompare(b.symbol));
console.log(`Found ${common.length} common tokens (price-filtered) out of ${Object.keys(mexcLookup).length} MEXC symbols`);
return common.map(t => ({ json: t }));
